#include <stdio.h>
#include <stdint.h>

static uint64_t gcd_uint64(uint64_t a, uint64_t b) {
    while (b) {
        uint64_t t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t A, B;
        scanf("%llu %llu", &A, &B);
        uint64_t g = gcd_uint64(A, B);
        while (g > 1) {
            B /= g;
            g = gcd_uint64(A, B);
        }
        if (B == 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

