#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it))
        B = int(next(it))
        g = math.gcd(A, B)
        while g > 1:
            B //= g
            g = math.gcd(A, B)
        out_lines.append('YES' if B == 1 else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

